/// GET v1/reportTypes
/// Lists report types.
///
/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `youtubereporting_report_types_list_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from youtubereporting_report_types_list_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn youtubereporting_report_types_list_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<ListReportTypesResponse>, ApiError>, P = ApiPending>
        + Send
        + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success { stream, status } => {
                let headers = status.headers().clone();

                if !status.is_success() {
                    return Err(ApiError::HttpStatus {
                        code: status.as_u16(),
                        headers,
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: ListReportTypesResponse = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status.as_u16(),
                    headers,
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

